+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+type ValueOf<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TData> ? TData : unknown;
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+export interface WindowDefinition {
+	name: string;
+	spec: WindowSpec;
+}
+
+type FrameBoundary = { readonly sql: string; readonly position: number };
+export interface WindowFrame { readonly mode: 'rows' | 'range'; readonly from: FrameBoundary; readonly to: FrameBoundary }
+
+export const unboundedPreceding: FrameBoundary = { sql: 'unbounded preceding', position: -Infinity };
+export const currentRow: FrameBoundary = { sql: 'current row', position: 0 };
+export const unboundedFollowing: FrameBoundary = { sql: 'unbounded following', position: Infinity };
+
+function offsetBoundary(name: 'preceding' | 'following', value: number): FrameBoundary {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+	return { sql: `${value} ${name}`, position: name === 'preceding' ? -value : value };
+}
+
+export function preceding(value: number): FrameBoundary { return offsetBoundary('preceding', value); }
+export function following(value: number): FrameBoundary { return offsetBoundary('following', value); }
+
+function frame(mode: WindowFrame['mode'], spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	if (spec.from.position > spec.to.position) throw new Error('Window frame "from" boundary must not follow the "to" boundary');
+	return { mode, ...spec };
+}
+
+export function rows(spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame { return frame('rows', spec); }
+export function range(spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame { return frame('range', spec); }
+
+function buildSpec(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy ? (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]) : [];
+	const orderBy = spec.orderBy ? (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]) : [];
+	const partitionSql = partitionBy.length ? sql`partition by ${sql.join(partitionBy, sql`, `)}` : undefined;
+	const orderSql = orderBy.length ? sql`order by ${sql.join(orderBy, sql`, `)}` : undefined;
+	const frameSql = spec.frame ? sql`${sql.raw(spec.frame.mode)} between ${sql.raw(spec.frame.from.sql)} and ${sql.raw(spec.frame.to.sql)}` : undefined;
+	return sql.join([partitionSql, orderSql, frameSql].filter((part): part is SQL => !!part), sql` `);
+}
+
+class WindowFunction<T> extends SQL<T> {
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this} over ${sql.identifier(spec)}`
+			: sql`${this} over (${buildSpec(spec)})`;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`.queryChunks);
+}
+
+function positiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer; received ${value}`);
+}
+
+function positional(value: number): SQL { return sql.raw(String(value)); }
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function ntile(buckets: number): WindowFunction<number> { positiveInteger('ntile', buckets); return windowFunction('ntile', [positional(buckets)]); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+
+export function lag<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null>;
+export function lag<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<ValueOf<T>, null> | ValueOf<TDefault>>;
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<ValueOf<T> | null> {
+	return windowFunction('lag', [value, ...(offset === undefined ? [] : [positional(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]);
+}
+export function lead<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null>;
+export function lead<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<ValueOf<T>, null> | ValueOf<TDefault>>;
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<ValueOf<T> | null> {
+	return windowFunction('lead', [value, ...(offset === undefined ? [] : [positional(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]);
+}
+export function firstValue<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null> { return windowFunction('first_value', [value]); }
+export function lastValue<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null> { return windowFunction('last_value', [value]); }
+export function nthValue<T extends SQLWrapper>(value: T, nth: number): WindowFunction<ValueOf<T> | null> { positiveInteger('nthValue', nth); return windowFunction('nth_value', [value, positional(nth)]); }
+
+export function windowSum(expression: SQLWrapper): WindowFunction<string | null> { return windowFunction('sum', [expression]); }
+export function windowAvg(expression: SQLWrapper): WindowFunction<string | null> { return windowFunction('avg', [expression]); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<ValueOf<T> | null> { return windowFunction('min', [expression]); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<ValueOf<T> | null> { return windowFunction('max', [expression]); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> { return windowFunction('count', [expression ?? sql.raw('*')]); }
