class WindowFunction<T> extends SQL<T> {
  over(spec: WindowSpec | string = {}): SQL<T> {
    return typeof spec === "string"
      ? sql`${this} over ${sql.identifier(spec)}`
      : sql`${this} over (${buildWindowSpec(spec)})`;
  }
}

function windowFunction<T>(
  name: string,
  args: SQLWrapper[] = [],
): WindowFunction<T> {
  return new WindowFunction(
    sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`.queryChunks,
  );
}

